 1→import { GraphCanvas } from "reagraph";
 2→import type { EntityKind } from "../../../shared/contracts";
 3→import type { InlineRelationshipGraphProps } from "../../../shared/chat-component-definitions";
 4→import { edgeStyle } from "../graph/graph-theme";
 5→import { useViewState } from "../../stores/view-state";
 6→
 7→// Resolved hex values for Reagraph/WebGL (same as server transform.ts).
 8→function nodeColor(kind: string): string {
 9→  switch (kind) {
10→    case "project": return "#3b82f6";
11→    case "feature": return "#14b8a6";
12→    case "task": return "#22c55e";
13→    case "decision": return "#eab308";
14→    case "question": return "#a855f7";
15→    case "observation": return "#ef4444";
16→    case "person": return "#f97316";
17→    case "workspace": return "#3b82f6";
18→    default: return "#9fbfe4";
19→  }
20→}
21→
22→export function InlineRelationshipGraph(props: InlineRelationshipGraphProps) {
23→  const navigateToGraph = useViewState((s) => s.navigateToGraph);
24→
25→  const nodes = props.nodes.map((node) => ({
26→    id: node.id,
27→    label: node.label,
28→    fill: nodeColor(node.kind),
29→    data: {
30→      kind: node.kind as EntityKind,
31→      connectionCount: props.edges.filter((e) => e.source === node.id || e.target === node.id).length,
32→    },
33→  }));
34→
35→  const edges = props.edges.map((edge) => {
36→    const style = edgeStyle(edge.type);
37→    return {
38→      id: edge.id,
39→      source: edge.source,
40→      target: edge.target,
41→      label: edge.label,
42→      fill: style.stroke,
43→      opacity: style.opacity,
44→      data: {
45→        type: edge.type,
46→        confidence: 1,
47→      },
48→    };
49→  });
50→
51→  function handleNodeClick(node: { id: string }) {
52→    const match = props.nodes.find((n) => n.id === node.id);
53→    if (match) {
54→      const entityId = `${match.kind}:${node.id}`;
55→      navigateToGraph(entityId);
56→      window.location.pathname = "/graph";
57→    }
58→  }
59→
60→  return (
61→    <section className="inline-relationship-graph">
62→      <p className="extraction-summary-title">{props.title}</p>
63→      <div style={{ height: 300, position: "relative" }}>
64→        <GraphCanvas
65→          nodes={nodes as any}
66→          edges={edges as any}
67→          selections={props.focusNodeIds ?? []}
68→          layoutType="forceDirected2d"
69→          sizingType="attribute"
70→          sizingAttribute="connectionCount"
71→          labelType="auto"
72→          onNodeClick={handleNodeClick}
73→        />
74→      </div>
75→    </section>
76→  );
77→}
