   8→  --card-foreground: oklch(0.94 0 0);
   9→  --muted: oklch(0.21 0.005 285);
  10→  --muted-foreground: oklch(0.55 0 0);
  11→  --border: oklch(0.26 0.005 285);
  12→  --input: oklch(0.26 0.005 285);
  13→  --ring: oklch(0.55 0.15 250);
  14→  --destructive: oklch(0.55 0.2 25);
  15→
  16→  /* Hover/active surface variants */
  17→  --hover: oklch(0.24 0.005 285);
  18→  --active: oklch(0.28 0.01 250);
  19→
  20→  /* Entity accent palette — OKLCH for perceptual uniformity */
  21→  --entity-project: oklch(0.65 0.15 250);
  22→  --entity-feature: oklch(0.65 0.15 170);
  23→  --entity-task: oklch(0.70 0.15 145);
  24→  --entity-decision: oklch(0.70 0.15 55);
  25→  --entity-question: oklch(0.65 0.15 300);
  26→  --entity-person: oklch(0.65 0.15 25);
  27→
  28→  /* Entity foregrounds — high contrast text on accent backgrounds */
  29→  --entity-project-fg: oklch(0.95 0.02 250);
  30→  --entity-feature-fg: oklch(0.95 0.02 170);
  31→  --entity-task-fg: oklch(0.95 0.02 145);
  32→  --entity-decision-fg: oklch(0.95 0.02 55);
  33→  --entity-question-fg: oklch(0.95 0.02 300);
  34→  --entity-person-fg: oklch(0.95 0.02 25);
  35→
  36→  /* Entity muted variants — for backgrounds, badges, subtle indicators */
  37→  --entity-project-muted: oklch(0.25 0.05 250);
  38→  --entity-feature-muted: oklch(0.25 0.05 170);
  39→  --entity-task-muted: oklch(0.25 0.05 145);
  40→  --entity-decision-muted: oklch(0.25 0.05 55);
  41→  --entity-question-muted: oklch(0.25 0.05 300);
  42→  --entity-person-muted: oklch(0.25 0.05 25);
  43→
  44→  /* Governance tiers */
  45→  --tier-blocking: oklch(0.60 0.20 25);
  46→  --tier-blocking-muted: oklch(0.22 0.04 25);
  47→  --tier-review: oklch(0.70 0.15 70);
  48→  --tier-review-muted: oklch(0.22 0.04 70);
  49→  --tier-awareness: oklch(0.65 0.15 145);
  50→  --tier-awareness-muted: oklch(0.22 0.04 145);
  51→}
